(function(){'use strict';function read(key){try{return JSON.parse(localStorage.getItem(key))||(key==='efi_adherence_v1'?{sessions:[]}:[]);}catch(e){return key==='efi_adherence_v1'?{sessions:[]}:[];}}
function readEvents(){return read('efi_assessment_events_v1');}
function readPlans(){return read('efi_action_plans_v1');}
function readAdherence(){return read('efi_adherence_v1');}
function readInterv(){return read('efi_intervention_v1');}
function readReflections(){return read('efi_reflections_v1');}
function countByProp(arr,prop){var counts={};arr.forEach(function(item){var val=item&&item[prop]?String(item[prop]):'unknown';counts[val]=(counts[val]||0)+1;});return counts;}
function pct(num,denom){if(!denom)return'—';return Math.round((num/denom)*100)+'%';}
function clearNode(node){while(node&&node.firstChild)node.removeChild(node.firstChild);}
function buildSection(title){return{title:title,rows:[],empty:''};}
function pushStatRow(section,label,value){section.rows.push({label:label,value:value});}
function renderSection(container,section){var heading=document.createElement('p');heading.style.fontWeight='600';heading.style.margin='var(--space-sm) 0 var(--space-xs) 0';heading.style.fontSize='0.9rem';heading.textContent=section.title;container.appendChild(heading);if(!section.rows.length){var empty=document.createElement('p');empty.style.color='var(--color-text-muted)';empty.style.fontSize='0.85rem';empty.textContent=section.empty||'No data yet.';container.appendChild(empty);return;}
section.rows.forEach(function(row){var wrap=document.createElement('div');wrap.style.display='flex';wrap.style.justifyContent='space-between';wrap.style.padding='4px 0';wrap.style.borderBottom='1px solid var(--color-border)';var label=document.createElement('span');label.textContent=row.label;var value=document.createElement('strong');value.textContent=String(row.value);wrap.appendChild(label);wrap.appendChild(value);container.appendChild(wrap);});}
function buildCurriculumStats(){var events=readEvents();var plans=readPlans();var pageViews=events.filter(function(e){return e.event_name==='page_view';});var moduleViews=pageViews.filter(function(e){return/^module-/.test(e.page||'');});var viewsByModule=countByProp(moduleViews,'page');var planEvents=events.filter(function(e){return e.event_name==='practice_plan_generated';});var completedModules={};planEvents.forEach(function(e){var mid=e.properties&&e.properties.module_id?e.properties.module_id:'unknown';completedModules[mid]=(completedModules[mid]||0)+1;});var passes=plans.filter(function(p){return p&&p.recheck&&p.recheck.cadence==='7d';}).length;var retakes=plans.filter(function(p){return p&&p.recheck&&p.recheck.cadence==='72h';}).length;var sections=[];var quizSection=buildSection('Quiz outcomes (this browser)');pushStatRow(quizSection,'Total plans generated',plans.length);pushStatRow(quizSection,'Passing results (7d cadence)',passes);pushStatRow(quizSection,'Needs-retake results (72h cadence)',retakes);pushStatRow(quizSection,'Pass rate',pct(passes,plans.length));sections.push(quizSection);var viewsSection=buildSection('Module page views');var moduleKeys=Object.keys(viewsByModule).sort();if(moduleKeys.length){moduleKeys.forEach(function(k){pushStatRow(viewsSection,k,viewsByModule[k]+' view'+(viewsByModule[k]===1?'':'s'));});}else{viewsSection.empty='No module page views recorded yet.';}
sections.push(viewsSection);var completionsSection=buildSection('Quiz completions by module');var completedKeys=Object.keys(completedModules).sort();if(completedKeys.length){completedKeys.forEach(function(k){pushStatRow(completionsSection,k,completedModules[k]+' quiz run'+(completedModules[k]===1?'':'s'));});}else{completionsSection.empty='No quiz completions recorded yet.';}
sections.push(completionsSection);return sections;}
function buildCoachingStats(){var events=readEvents();var reflections=readReflections();var planStarts=events.filter(function(e){return e.event_name==='practice_plan_started';}).length;var checkins=events.filter(function(e){return e.event_name==='practice_checkin_completed';}).length;var transferLogs=events.filter(function(e){return e.event_name==='behavior_transfer_logged';}).length;var rechecksDue=events.filter(function(e){return e.event_name==='spaced_recheck_due';}).length;var ratings=[];events.forEach(function(e){if(e.event_name==='practice_checkin_completed'&&e.properties&&e.properties.self_rating){ratings.push(Number(e.properties.self_rating));}});var avgRating=ratings.length?(ratings.reduce(function(a,b){return a+b;},0)/ratings.length).toFixed(1):'—';var sections=[];var engagementSection=buildSection('Plan engagement');pushStatRow(engagementSection,'Plans started',planStarts);pushStatRow(engagementSection,'Check-ins completed',checkins);pushStatRow(engagementSection,'Transfer evidence logs',transferLogs);pushStatRow(engagementSection,'Spaced rechecks triggered',rechecksDue);pushStatRow(engagementSection,'Avg self-rating (1-5)',avgRating+(ratings.length?' ('+ratings.length+' ratings)':''));sections.push(engagementSection);var reflectionsSection=buildSection('Reflections');pushStatRow(reflectionsSection,'Total reflections saved',reflections.length);var bySource=countByProp(reflections,'source_tool');Object.keys(bySource).sort().forEach(function(k){pushStatRow(reflectionsSection,'  from '+k,bySource[k]);});sections.push(reflectionsSection);var authedEvents=events.filter(function(e){return e.user_id;});var uniqueUsers={};authedEvents.forEach(function(e){uniqueUsers[e.user_id]=true;});var userCount=Object.keys(uniqueUsers).length;var usersSection=buildSection('User attribution');pushStatRow(usersSection,'Events with user_id attached',authedEvents.length);pushStatRow(usersSection,'Distinct authenticated users',userCount||'—');sections.push(usersSection);return sections;}
function buildAdherenceStats(){var adherenceData=readAdherence();var sessions=Array.isArray(adherenceData.sessions)?adherenceData.sessions:[];var computed=adherenceData.computed||{};var totalSessions=sessions.length;var completedSessions=sessions.filter(function(s){return s.completed;}).length;var recentSessions=sessions.slice(-10);var recentCompleted=recentSessions.filter(function(s){return s.completed;}).length;var interv=readInterv();var intervMeta=(Array.isArray(interv)?{}:interv)||{};var events=readEvents();var intervShown=events.filter(function(e){return e.event_name==='low_adherence_intervention_shown';}).length;var intervDismissed=events.filter(function(e){return e.event_name==='low_adherence_intervention_dismissed';}).length;var sections=[];var adherenceSection=buildSection('Session adherence');pushStatRow(adherenceSection,'Total sessions recorded',totalSessions);pushStatRow(adherenceSection,'Completed sessions',completedSessions);pushStatRow(adherenceSection,'Overall completion rate',pct(completedSessions,totalSessions));pushStatRow(adherenceSection,'Recent 10 sessions completed',recentCompleted+' / '+recentSessions.length);pushStatRow(adherenceSection,'Current adherence level',computed.level?computed.level.toUpperCase():'—');pushStatRow(adherenceSection,'Adherence score (0–1)',typeof computed.score==='number'?computed.score.toFixed(2):'—');sections.push(adherenceSection);var interventionSection=buildSection('Intervention history');pushStatRow(interventionSection,'Times intervention shown',intervShown);pushStatRow(interventionSection,'Times dismissed',intervDismissed);if(intervMeta.last_shown_at){pushStatRow(interventionSection,'Last shown',new Date(intervMeta.last_shown_at).toLocaleString());}
if(intervMeta.show_count){pushStatRow(interventionSection,'Total show count (meta)',intervMeta.show_count);}
sections.push(interventionSection);var moduleSection=buildSection('Module breakdown (last 20 sessions)');var byModule=countByProp(sessions.slice(-20),'moduleId');var mkeys=Object.keys(byModule).sort();if(mkeys.length){mkeys.forEach(function(k){pushStatRow(moduleSection,k||'unknown',byModule[k]+' session'+(byModule[k]===1?'':'s'));});}else{moduleSection.empty='No session data yet.';}
sections.push(moduleSection);return sections;}
function render(){var currEl=document.getElementById('analytics-curriculum-body');var coachEl=document.getElementById('analytics-coaching-body');var adhrEl=document.getElementById('analytics-adherence-body');var statusEl=document.getElementById('analytics-refresh-status');if(currEl){clearNode(currEl);buildCurriculumStats().forEach(function(section){renderSection(currEl,section);});}
if(coachEl){clearNode(coachEl);buildCoachingStats().forEach(function(section){renderSection(coachEl,section);});}
if(adhrEl){clearNode(adhrEl);buildAdherenceStats().forEach(function(section){renderSection(adhrEl,section);});}
if(statusEl)statusEl.textContent='Last refreshed: '+new Date().toLocaleTimeString();}
document.addEventListener('DOMContentLoaded',function(){if(!document.getElementById('analytics-curriculum-body'))return;render();var refreshBtn=document.getElementById('analytics-refresh-btn');if(refreshBtn){refreshBtn.addEventListener('click',function(){render();});}});})();